() => {
  // Forzar color verde en el ícono video_settings
  const vsIcon = document.querySelector('gs-icon[aria-label="video_settings"]');
  if (vsIcon) {
    vsIcon.querySelectorAll('svg path').forEach(p => p.style.setProperty('fill', '#00E5CC', 'important'));
    vsIcon.style.setProperty('color', '#00E5CC', 'important');
  }

  // Posicionar tooltip 'Configuración de Cálculo' bajo el botón video_settings
  const setupBtn = document.querySelector('otto-web-setup-calculation-engine-button button');
  const tip = Array.from(document.querySelectorAll('gs-tooltip')).find(t => (t.textContent || '').includes('Configuración de Cálculo'));
  if (!setupBtn || !tip) return;

  const tipWrap = tip.closest('.cdk-overlay-connected-position-bounding-box');
  if (tipWrap) {
    tipWrap.style.left = '0px';
    tipWrap.style.top = '0px';
    tipWrap.style.width = '100vw';
    tipWrap.style.height = '100vh';
    tipWrap.style.position = 'fixed';
    tipWrap.style.display = 'block';
    tipWrap.style.transform = 'none';
  }

  const pane = tip.closest('.cdk-overlay-pane');
  if (pane) {
    pane.style.position = 'fixed';
    pane.style.transform = 'none';
  }

  tip.style.position = 'fixed';
  tip.style.margin = '0';
  tip.style.transform = 'none';

  const br = setupBtn.getBoundingClientRect();
  const tr = tip.getBoundingClientRect();
  const left = Math.max(8, Math.round(br.left + (br.width / 2) - (tr.width / 2)));
  const top = Math.round(br.bottom + 10);

  tip.style.left = `${left}px`;
  tip.style.top = `${top}px`;
}
